INSERT INTO "persons" ("id", "display_name", "spoken_name", "birth_year", "birth_date", "onboarded_at", "biographical_anchors", "life_status", "account_id", "created_at", "updated_at") VALUES ('230f4a0b-3637-4ce5-8a72-e73d2c0e2067', 'Eleanor Boudreaux', 'Eleanor', '1956', '1956-12-18', '2026-06-30 15:19:34.821+00', '{"hometown": "Zachary, LA", "hasChildren": true, "siblingContext": "Youngest of five", "currentLocation": "New Orleans — moved from Mandeville in 2017, previously lived in Raleigh, NC from 1987-1991", "hasGrandchildren": true, "occupationSummary": "Worked at IBM and in the IBM ecosystem for most of their life, holding roles in development and sales."}', 'living', '4b36d9ab-a788-4a7e-94d4-6cfb062a6e38', '2026-06-30 15:19:06.935+00', '2026-06-30 15:35:12.319+00');
INSERT INTO "prose_revisions" ("id", "seq", "story_id", "level", "text", "model_id", "prompt_text", "actor_person_id", "created_at") VALUES ('17221d48-45c3-4e83-af21-3c45c7019178', '1', 'b2b05dc3-3e08-4e17-9c42-557e1b669c60', 'ai_transcribed', 'Oh, my grandmother. Her name was Odette and she lived down by the bayou. She used to say she could tell the weather by the way the Spanish moss moved. I must have been four or five the first time she let me help her shell butter beans on the porch. I can still smell that afternoon.', 'mock-whisper-turbo', NULL, NULL, '2026-06-30 04:14:34.09+00');
INSERT INTO "prose_revisions" ("id", "seq", "story_id", "level", "text", "model_id", "prompt_text", "actor_person_id", "created_at") VALUES ('1ebda418-4817-4260-a726-d76b2d40a1b4', '2', 'b2b05dc3-3e08-4e17-9c42-557e1b669c60', 'ai_polished', 'Her name was Odette, and she lived down by the bayou. She used to say she could tell the weather by the way the Spanish moss moved — and I believed her. My earliest memory of her is sitting on her porch, four or five years old, helping shell butter beans in the afternoon heat. I can still smell that afternoon.', 'mock-claude', '[dev-seed] representative render system prompt', NULL, '2026-06-30 04:14:34.098+00');
INSERT INTO "stories" ("id", "owner_person_id", "state", "audience_tier", "recording_media_id", "transcript", "transcript_word_timings", "prose", "title", "summary", "tags", "era_year", "era_label", "prompt_question", "ask_id", "approved_at", "created_at", "updated_at") VALUES ('4622e593-b45a-495c-ab83-23b83b4047d0', '94a20bc4-365c-43c9-81fe-1e0824663666', 'shared', 'family', '047fd6e7-a266-4f88-b332-a012243bf9fd', 'We met at a dance hall in 1961. He couldn''t dance a step, but he made me laugh.', NULL, 'We met at a dance hall in the autumn of 1961. He couldn''t dance a single step to save his life, but he made me laugh so hard I forgot to mind my own feet.', 'The dance at the Blue Room', 'Eleanor remembers the night she met Grandpa — and how badly he danced.', '["marriage", "family", "louisiana"]', '1961', 'the Blue Room', 'How did you and Grandpa meet?', NULL, '1961-10-12 00:00:00+00', '1961-10-12 00:00:00+00', '2026-06-30 04:14:34.423+00');
INSERT INTO "stories" ("id", "owner_person_id", "state", "audience_tier", "recording_media_id", "transcript", "transcript_word_timings", "prose", "title", "summary", "tags", "era_year", "era_label", "prompt_question", "ask_id", "approved_at", "created_at", "updated_at") VALUES ('b2b05dc3-3e08-4e17-9c42-557e1b669c60', '94a20bc4-365c-43c9-81fe-1e0824663666', 'pending_approval', 'private', '1b82b31b-d036-45ee-b3c4-7cf50f5dd928', 'Oh, my grandmother. Her name was Odette and she lived down by the bayou. She used to say she could tell the weather by the way the Spanish moss moved. I must have been four or five the first time she let me help her shell butter beans on the porch. I can still smell that afternoon.', NULL, 'Her name was Odette, and she lived down by the bayou. She used to say she could tell the weather by the way the Spanish moss moved — and I believed her. My earliest memory of her is sitting on her porch, four or five years old, helping shell butter beans in the afternoon heat. I can still smell that afternoon.', 'My grandmother Odette', 'Eleanor''s earliest memory of her grandmother shelling butter beans on the bayou porch.', '["grandparents", "childhood", "louisiana"]', '1947', 'the bayou', 'Grandma, what''s your earliest memory of your own grandmother?', '4c9e14c7-a7c1-4be0-aa5e-357abc734696', NULL, '2026-06-30 04:14:34.07+00', '2026-06-30 04:14:34.118+00');
INSERT INTO "stories" ("id", "owner_person_id", "state", "audience_tier", "recording_media_id", "transcript", "transcript_word_timings", "prose", "title", "summary", "tags", "era_year", "era_label", "prompt_question", "ask_id", "approved_at", "created_at", "updated_at") VALUES ('cbd7309a-1d00-46de-b63f-15c16a782260', '94a20bc4-365c-43c9-81fe-1e0824663666', 'shared', 'family', '42cedf78-0a06-4dee-8575-58432deefa90', 'The house on Cherry Street had a wide front porch where my mother kept her ferns. In the summer the cicadas would start up at dusk and you could hear them from the kitchen.', NULL, 'The house on Cherry Street had a wide front porch where my mother kept her ferns. In summer, the cicadas would start up at dusk, loud enough to carry into the kitchen.', 'The porch on Cherry Street', 'Eleanor remembers her mother''s ferns and the cicadas at dusk.', '["childhood", "house", "louisiana"]', '1958', 'Cherry Street', 'Tell me about the house you grew up in.', NULL, '1958-06-15 00:00:00+00', '1958-06-15 00:00:00+00', '2026-06-30 04:14:34.365+00');
INSERT INTO "stories" ("id", "owner_person_id", "state", "audience_tier", "recording_media_id", "transcript", "transcript_word_timings", "prose", "title", "summary", "tags", "era_year", "era_label", "prompt_question", "ask_id", "approved_at", "created_at", "updated_at") VALUES ('2989a033-a201-4983-bdef-9a7cf9d14dd6', '94a20bc4-365c-43c9-81fe-1e0824663666', 'shared', 'family', 'da3cefcd-6a51-4540-8f1f-26ada04d0cf9', 'We married in the spring of 1963. It rained, and everyone said that was good luck.', NULL, 'We married on a wet morning in the spring of 1963. It poured the whole way to the church, and every aunt I had told me rain on your wedding day was the best luck a marriage could ask for.', 'Rain on the wedding', 'A rainy 1963 wedding that the whole family swore was good luck.', '["marriage", "family"]', '1963', NULL, 'What was your wedding day like?', NULL, '1963-04-06 00:00:00+00', '1963-04-06 00:00:00+00', '2026-06-30 04:14:34.468+00');
INSERT INTO "stories" ("id", "owner_person_id", "state", "audience_tier", "recording_media_id", "transcript", "transcript_word_timings", "prose", "title", "summary", "tags", "era_year", "era_label", "prompt_question", "ask_id", "approved_at", "created_at", "updated_at") VALUES ('586f96b5-182f-4f6b-83a1-37d355efe2e5', '94a20bc4-365c-43c9-81fe-1e0824663666', 'shared', 'family', 'f8322a92-5d28-44a6-a64b-0a4ae8a06339', 'Your father was born in 1965, and the house got a lot louder after that.', NULL, 'Your father came along in 1965, and that little house on Cherry Street got a great deal louder — and a great deal happier — overnight.', 'The house gets louder', 'Eleanor on the year her first child was born.', '["birth", "family", "house"]', '1965', 'Cherry Street', 'Tell me about the year the children were born.', NULL, '1965-07-22 00:00:00+00', '1965-07-22 00:00:00+00', '2026-06-30 04:14:34.515+00');
INSERT INTO "stories" ("id", "owner_person_id", "state", "audience_tier", "recording_media_id", "transcript", "transcript_word_timings", "prose", "title", "summary", "tags", "era_year", "era_label", "prompt_question", "ask_id", "approved_at", "created_at", "updated_at") VALUES ('d708360a-f737-4936-a0fa-0d2db02c529e', '94a20bc4-365c-43c9-81fe-1e0824663666', 'shared', 'family', 'e07fddb6-5ed9-4b4f-9b0a-c3b8e51f186f', 'I taught school for thirty years, third grade mostly. I loved the noisy ones.', NULL, 'I taught school for thirty years — third grade, mostly. People always pity the teacher with the noisy class, but those were the ones I loved best.', 'Thirty years of third grade', 'Eleanor''s decades teaching — and her soft spot for the loud kids.', '["work", "louisiana"]', '1974', NULL, 'What work did you do?', NULL, '1974-09-03 00:00:00+00', '1974-09-03 00:00:00+00', '2026-06-30 04:14:34.561+00');
